using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public sealed class WeatherTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    public WeatherTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool(Name = "get_current_weather", ReadOnly = true),
     Description("Gets the current weather for a given city name.")]
    public async Task<string> GetCurrentWeather(
        [Description("City name, e.g. 'London' or 'New York'")] string city,
        CancellationToken cancellationToken)
    {
        using var client = _httpClientFactory.CreateClient("WeatherApi");

        var response = await client.GetAsync(
            $"current.json?q={Uri.EscapeDataString(city)}",
            cancellationToken);

        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(
            await response.Content.ReadAsStreamAsync(cancellationToken),
            cancellationToken: cancellationToken);

        var current = doc.RootElement.GetProperty("current");
        return $"""
            Weather for {city}:
              Temperature: {current.GetProperty("temp_c")}°C / {current.GetProperty("temp_f")}°F
              Condition:   {current.GetProperty("condition").GetProperty("text")}
              Humidity:    {current.GetProperty("humidity")}%
              Wind:        {current.GetProperty("wind_kph")} km/h {current.GetProperty("wind_dir")}
            """;
    }

    [McpServerTool(Name = "get_forecast", ReadOnly = true),
     Description("Gets a multi-day weather forecast for a given city.")]
    public async Task<string> GetForecast(
        [Description("City name, e.g. 'London'")] string city,
        [Description("Number of forecast days (1-3)")] int days,
        CancellationToken cancellationToken)
    {
        days = Math.Clamp(days, 1, 3);
        using var client = _httpClientFactory.CreateClient("WeatherApi");

        var response = await client.GetAsync(
            $"forecast.json?q={Uri.EscapeDataString(city)}&days={days}",
            cancellationToken);

        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(
            await response.Content.ReadAsStreamAsync(cancellationToken),
            cancellationToken: cancellationToken);

        var forecastDays = doc.RootElement
            .GetProperty("forecast")
            .GetProperty("forecastday")
            .EnumerateArray();

        var lines = new List<string> { $"Forecast for {city}:" };
        foreach (var day in forecastDays)
        {
            var d = day.GetProperty("day");
            lines.Add($"""
                  {day.GetProperty("date")}:
                    High: {d.GetProperty("maxtemp_c")}°C  Low: {d.GetProperty("mintemp_c")}°C
                    Condition: {d.GetProperty("condition").GetProperty("text")}
                    Rain chance: {d.GetProperty("daily_chance_of_rain")}%
                """);
        }
        return string.Join("\n", lines);
    }
}

